const hamMenu=document.getElementById("hamMenu"),offScreenNav=document.getElementById("offScreenNav"),handleHamAnimations=()=>{hamMenu.classList.toggle("animate"),offScreenNav.classList.toggle("show")};hamMenu.addEventListener("click",handleHamAnimations),offScreenNav.addEventListener("click",handleHamAnimations);const particalBoard=document.querySelector(".partical-board"),config={particalCount:200};for(let a=0;a<config.particalCount;a++)createPartical(),positionPartical();function createPartical(){let a=document.createElement("div");a.classList.add("partical"),particalBoard.appendChild(a)}function positionPartical(a){let t=document.querySelectorAll(".partical");for(let a=0;a<t.length/2;a++)t[a].classList.add("mobile");t.forEach((a=>{let t=Math.floor(-1400*Math.random()+700);a.style.top=`${t}%`;let e=Math.floor(-1400*Math.random()+700);a.style.left=`${e}%`;let n=Math.floor(50*Math.random()),o=Math.floor(1*Math.random());a.style.animation=`particals ${n}s ${o}s ease infinite`}))}